import os
import argparse
import logging
import tensorflow.compat.v1 as tf

tf.disable_v2_behavior()

tf.compat.v1.disable_eager_execution()  # Ensures graph is modified before been saved

if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO)

    # Defining arguments of the script
    parser = argparse.ArgumentParser(
        description="Convert Tensorflow checkpoint to protobuf freezed graph model."
    )
    parser.add_argument(
        "checkpoint_meta_path", help="Meta file (.meta) related to the checkpoint"
    )
    parser.add_argument(
        "protobuf_path", help="Filename of the output protobuf file (.pb)"
    )
    parser.add_argument(
        "--disp-nodes",
        help="Displays the list of nodes, useful to define desired output nodes",
        action="store_true",
    )
    parser.add_argument(
        "output_nodes",
        nargs="+",
        help="Set of output nodes that will be embeded in the protobuf",
    )

    args = parser.parse_args()

    with tf.Session() as sess:
        # Restore the graph
        logging.info("Loading checkpoint ...")
        saver = tf.train.import_meta_graph(args.checkpoint_meta_path)
        saver.restore(sess, args.checkpoint_meta_path.replace(".meta", ""))
        logging.info("Graph was successfully loaded")

        # Retrieve graph defintion
        gd = sess.graph.as_graph_def()

        # If required, displays the entire list of nodes in the graph
        # This comes handy to retrieve the exact name of the desired
        # output nodes
        if args.disp_nodes:
            print("Nodes list of the graph:")
            for node in gd.node:
                print("\t", node.name)

        # Modify nodes to freezed-state nodes
        for node in gd.node:
            if node.op == "RefSwitch":
                node.op = "Switch"
                for index in range(len(node.input)):
                    if "moving_" in node.input[index]:
                        node.input[index] = node.input[index] + "/read"
            elif node.op == "AssignSub":
                node.op = "Sub"
                if "use_locking" in node.attr:
                    del node.attr["use_locking"]
            elif node.op == "AssignAdd":
                node.op = "Add"
                if "use_locking" in node.attr:
                    del node.attr["use_locking"]
            elif node.op == "Assign":
                node.op = "Identity"
                if "use_locking" in node.attr:
                    del node.attr["use_locking"]
                if "validate_shape" in node.attr:
                    del node.attr["validate_shape"]
                if len(node.input) == 2:
                    # input0: ref: Should be from a Variable node. May be uninitialized.
                    # input1: value: The value to be assigned to the variable.
                    node.input[0] = node.input[1]
                    del node.input[1]

        # Converts modified graph to constants
        converted_graph_def = tf.graph_util.convert_variables_to_constants(
            sess, gd, args.output_nodes
        )

        # Exports protobuf file
        logging.info("Graph successfully freezed, exporting .pb file ...")
        basedir, basename = os.path.split(args.protobuf_path)
        tf.train.write_graph(converted_graph_def, basedir, basename, as_text=False)
        logging.info("Frozen graph has been successfully exported.")
